/**
* Commit the changes.
* <p>
* This method does nothing if there are no unsaved changes,
* otherwise it increments the current version
* and stores the data (for file based stores).
* <p>
* It is not necessary to call this method when auto-commit is enabled (the default
* setting), as in this case it is automatically called from time to time or
* when enough changes have accumulated. However, it may still be called to
* flush all changes to disk.
* <p>
* At most one store operation may run at any time.
*
* @return the new version (incremented if there were changes)
*/
    public long commit() {
        return commit(x -> true);
    }

    private long commit(Predicate<MVStore> check) {
        // we need to prevent re-entrance, which may be possible,
        // because meta map is modified within storeNow() and that
        // causes beforeWrite() call with possibility of going back here
        if(!storeLock.isHeldByCurrentThread() || currentStoreVersion < 0) {
            storeLock.lock();
            try {
                if (check.test(this)) {
                    store(true);
                }
            } finally {
                unlockAndCheckPanicCondition();
            }
        }
        return currentVersion;
    }

/**
* Commit a transaction.
*  @param t transaction to commit
*  @param recovery if called during initial transaction recovery procedure
*                  therefore undo log is stored under "committed" name already
*/
    void commit(Transaction t, boolean recovery) {
        if (!store.isClosed()) {
            int transactionId = t.transactionId;
            // First, mark log as "committed".
            // It does not change the way this transaction is treated by others,
            // but preserves fact of commit in case of abrupt termination.
            MVMap<Long,Record<?,?>> undoLog = undoLogs[transactionId];
            Cursor<Long,Record<?,?>> cursor;
            if(recovery) {
                removeUndoLogRecord(transactionId);
                cursor = undoLog.cursor(null);
            } else {
                cursor = undoLog.cursor(null);
                markUndoLogAsCommitted(transactionId);
            }

            // this is an atomic action that causes all changes
            // made by this transaction, to be considered as "committed"
            flipCommittingTransactionsBit(transactionId, true);

            CommitDecisionMaker<Object> commitDecisionMaker = new CommitDecisionMaker<>();
            try {
                while (cursor.hasNext()) {
                    Long undoKey = cursor.next();
                    Record<?,?> op = cursor.getValue();
                    int mapId = op.mapId;
                    MVMap<Object, VersionedValue<Object>> map = openMap(mapId);
                    if (map != null && !map.isClosed()) { // might be null if map was removed later
                        Object key = op.key;
                        commitDecisionMaker.setUndoKey(undoKey);
                        // second parameter (value) is not really
                        // used by CommitDecisionMaker
                        map.operate(key, null, commitDecisionMaker);
                    }
                }
            } finally {
                try {
                    undoLog.clear();
                } finally {
                    flipCommittingTransactionsBit(transactionId, false);
                }
            }
        }
    }

/**
* Commit the transaction. Afterwards, this transaction is closed.
*/
    public void commit() {
        assert store.openTransactions.get().get(transactionId);
        markTransactionEnd();
        Throwable ex = null;
        boolean hasChanges = false;
        int previousStatus = STATUS_OPEN;
        try {
            long state = setStatus(STATUS_COMMITTED);
            hasChanges = hasChanges(state);
            previousStatus = getStatus(state);
            if (hasChanges) {
                store.commit(this, previousStatus == STATUS_COMMITTED);
            }
        } catch (Throwable e) {
            ex = e;
            throw e;
        } finally {
            if (isActive(previousStatus)) {
                try {
                    store.endTransaction(this, hasChanges);
                } catch (Throwable e) {
                    if (ex == null) {
                        throw e;
                    } else {
                        ex.addSuppressed(e);
                    }
                }
            }
        }
    }

